SELECT version_number, version_date
FROM experiment_versions
WHERE experiment_id = 1;

SELECT plate_type
FROM plates
WHERE plate_conditions LIKE '%pH 7.0, 25°C%';

SELECT plate_number, plate_type
FROM plates
WHERE plate_id = 1;

SELECT DISTINCT r.researcher_name, r.email
FROM researchers r
JOIN experiment_researchers er ON r.researcher_id = er.researcher_id;

SELECT COUNT(DISTINCT experiment_id)
FROM experiment_researchers
WHERE role_in_experiment = 'Co-Investigator';

SELECT experiment_name
FROM experiments
WHERE experiment_type = 'Enzyme Kinetics' AND version > 1;
